    for (final item in items) {
      if (item.quantity <= 0) {
        return Left(ValidationFailure('Quantity must be positive'));
      }
      if (item.quantity > 99) {
        return Left(ValidationFailure('Max quantity per item is 99'));
      }
    }

    return const Right(null);
  }
}

